    example: "// Before: prop drilling through Header and Toolbar just to reach ThemedButton\nfunction ThemedButtonDrilled({ theme }) {\n  return <button>Theme is {theme}</button>;\n}\n\nfunction ToolbarDrilled({ theme }) {\n  return <ThemedButtonDrilled theme={theme} />;\n}\n\nfunction HeaderDrilled({ theme }) {\n  return <ToolbarDrilled theme={theme} />;\n}\n\n// After: Context skips the middle layers\nconst ThemeContext = React.createContext('light');\n\nfunction ThemedButton() {\n  const theme = React.useContext(ThemeContext);\n  return <button>Theme is {theme}</button>;\n}\n\nfunction Toolbar() {\n  return <ThemedButton />;\n}\n\nfunction Header() {\n  return <Toolbar />;\n}\n\nfunction App() {\n  return (\n    <div>\n      <HeaderDrilled theme=\"dark\" />\n      <ThemeContext.Provider value=\"dark\">\n        <Header />\n      </ThemeContext.Provider>\n    </div>\n  );\n}\n\nReactDOM.createRoot(document.getElementById('root')).render(<App />);",
