    example: "function wait(ms, value) {\n  return new Promise(resolve => setTimeout(() => resolve(value), ms));\n}\n\nfunction useFetch(fetchFn, deps) {\n  const [loading, setLoading] = React.useState(true);\n  const [data, setData] = React.useState(null);\n  const [error, setError] = React.useState(null);\n\n  React.useEffect(() => {\n    setLoading(true);\n    setError(null);\n    fetchFn()\n      .then(result => setData(result))\n      .catch(err => setError(err.message))\n      .finally(() => setLoading(false));\n  }, deps);\n\n  return { loading, data, error };\n}\n\nfunction Joke() {\n  const { loading, data, error } = useFetch(() => wait(1000, 'Why do programmers prefer dark mode? Light attracts bugs.'), []);\n\n  if (loading) return <p>Loading joke...</p>;\n  if (error) return <p>Error: {error}</p>;\n  return <p>{data}</p>;\n}\n\nReactDOM.createRoot(document.getElementById('root')).render(<Joke />);",
