    example: "function useDebouncedValue(value, delay) {\n  const [debounced, setDebounced] = React.useState(value);\n\n  React.useEffect(() => {\n    const id = setTimeout(() => setDebounced(value), delay);\n    return () => clearTimeout(id);\n  }, [value, delay]);\n\n  return debounced;\n}\n\nfunction SearchBox() {\n  const [query, setQuery] = React.useState('');\n  const debouncedQuery = useDebouncedValue(query, 500);\n\n  return (\n    <div>\n      <input value={query} onChange={e => setQuery(e.target.value)} placeholder=\"Type to search...\" />\n      <p>Typing now: {query}</p>\n      <p>Debounced (used for searching): {debouncedQuery}</p>\n    </div>\n  );\n}\n\nReactDOM.createRoot(document.getElementById('root')).render(<SearchBox />);",
    starterCode: "function useDebouncedValue(value, delay) {\n  const [debounced, setDebounced] = React.useState(value);\n\n  React.useEffect(() => {\n    const id = setTimeout(() => setDebounced(value), delay);\n    return () => clearTimeout(id);\n  }, [value, delay]);\n\n  return debounced;\n}\n\nfunction LiveSearch() {\n  const [text, setText] = React.useState('');\n  const debouncedText = useDebouncedValue(text, 400);\n\n  return (\n    <div>\n      <input value={text} onChange={e => setText(e.target.value)} placeholder=\"Search...\" />\n      <p>Searching for: {debouncedText || '(nothing yet)'}</p>\n    </div>\n  );\n}\n\nReactDOM.createRoot(document.getElementById('root')).render(<LiveSearch />);",
